import { describe, it, expect } from 'vitest';

describe('happy-dom click bubbling probe', () => {
  it('bubbles element.click() up to a document-level click listener', () => {
    let docHits = 0;
    const handler = () => { docHits++; };
    document.addEventListener('click', handler);
    const el = document.createElement('div');
    document.body.append(el);
    el.click();
    el.remove();
    document.removeEventListener('click', handler);
    expect(docHits).toBe(1);
  });

  it('dispatchEvent(click, bubbles:true) reaches a document listener', () => {
    let docHits = 0;
    const handler = () => { docHits++; };
    document.addEventListener('click', handler);
    document.body.dispatchEvent(new MouseEvent('click', { bubbles: true }));
    document.removeEventListener('click', handler);
    expect(docHits).toBe(1);
  });
});
